infix fun Int.powerOf(exp: Int): Int {
    var result = 1
    for (i in 1..exp) result *= this
    return result
}

fun main() {
    // Using infix notation
    println(2 powerOf 3)   // 8
    println(5 powerOf 2)   // 25

    // Standard library infix
    val pair = "language" to "Kotlin"
    println(pair)  // (language, Kotlin)

    val range = 1..10 step 2
    println(range.toList())  // [1, 3, 5, 7, 9]
}
